+		info, err := entry.Info()
+		if err != nil {
+			continue
+		}
+		if selected == "" || info.ModTime().After(newest) {
+			newest = info.ModTime()
+			selected = filepath.Join(outputDir, name)
+		}
+	}
+	return selected
+}
