+
+	alerts := GenerateAlerts([]*Prediction{approaching, imminent}, DefaultAlertOptions())
+
+	if findAlert(alerts, AlertApproachingLimit, "work") == nil {
+		t.Fatalf("expected approaching alert for work profile")
